102	// ReconcilePlan is a single proposed or applied lifecycle repair.
103	type ReconcilePlan struct {
104		BeadID         string         `json:"bead_id"`
105		Reason         string         `json:"reason"`
106		CurrentFields  map[string]any `json:"current_fields,omitempty"`
107		SetFields      map[string]any `json:"set_fields,omitempty"`
108		ClearFields    []string       `json:"clear_fields,omitempty"`
109		RemoveLabels   []string       `json:"remove_labels,omitempty"`
110		AddLabels      []string       `json:"add_labels,omitempty"`
111		TargetStatus   string         `json:"target_status,omitempty"`
112		CloseSatisfied bool           `json:"close_satisfied,omitempty"`
113		Applied        bool           `json:"applied"`
114	}
115	
116	// ReconcileLifecycleMetadata returns conservative repairs for stale
117	// no_changes management fields. With Apply=false it is a dry run; with
118	// Apply=true it mutates through the Store API and appends reconciliation
119	// evidence.
120	func (s *Store) ReconcileLifecycleMetadata(opts ReconcileOptions) ([]ReconcilePlan, error) {
121		if opts.Now.IsZero() {
122			opts.Now = time.Now().UTC()
123		}
124		beads, err := s.ReadAll(context.Background())
125		if err != nil {
126			return nil, err
127		}
128		childrenByParent := make(map[string]int)
129		nonTerminalChildrenByParent := make(map[string]int)
130		closedChildrenByParent := make(map[string]int)
131		idFilter := make(map[string]bool, len(opts.IDs))
132		for _, id := range opts.IDs {
133			if strings.TrimSpace(id) != "" {
134				idFilter[strings.TrimSpace(id)] = true
135			}
136		}
137		for _, b := range beads {
138			if b.Parent != "" {
139				childrenByParent[b.Parent]++
140				if b.Status != StatusClosed && b.Status != StatusCancelled {
141					nonTerminalChildrenByParent[b.Parent]++
142				}
143				if b.Status == StatusClosed {
144					closedChildrenByParent[b.Parent]++
145				}
146			}
147		}
148	
149		var plans []ReconcilePlan
150		for _, b := range beads {
151			if len(idFilter) > 0 && !idFilter[b.ID] {
152				continue
153			}
154			events, _ := s.eventsForBead(&b)
155			if p, ok := planLifecycleReconcile(b, events, childrenByParent[b.ID], nonTerminalChildrenByParent[b.ID], closedChildrenByParent[b.ID], opts.Now); ok {
156				if opts.Apply {
157					if err := s.applyReconcilePlan(p); err != nil {
158						return plans, err
159					}
160					p.Applied = true
161				}
162				plans = append(plans, p)
163			}
164		}
165		return plans, nil
166	}
167	
168	func planLifecycleReconcile(b Bead, events []BeadEvent, childCount, nonTerminalChildCount, closedChildCount int, now time.Time) (ReconcilePlan, bool) {
169		p := ReconcilePlan{
170			BeadID:        b.ID,
171			CurrentFields: currentLifecycleFields(b),
172		}
173		latest := latestLifecycleEvent(events)
174	
175		if b.Status == StatusClosed && hasClosedNoChangesResidue(b) {
176			p.Reason = "closed bead has stale no_changes lifecycle metadata"
177			p.ClearFields = noChangesFieldsPresent(b)
178			p.RemoveLabels = noChangesLabelsPresent(b)
179			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
180		}
181	
182		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
183			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
184			p.ClearFields = noChangesFieldsPresent(b)
185			p.RemoveLabels = noChangesLabelsPresent(b)
186			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
187		}
188	
189		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
190			p.Reason = "verified no_changes evidence closes as already_satisfied"
191			p.ClearFields = noChangesFieldsPresent(b)
192			p.RemoveLabels = noChangesLabelsPresent(b)
193			p.TargetStatus = StatusClosed
194			p.CloseSatisfied = true
195			return p, true
196		}
197	
198		if isExpiredRetryAfter(b, now) {
199			p.Reason = "expired retry-after metadata no longer blocks execution"
200			p.ClearFields = []string{ExtraRetryAfter}
201			return p, true
202		}
203	
204		if isEpicBead(b) && childCount > 0 && nonTerminalChildCount == 0 && b.Status != StatusClosed && b.Status != StatusCancelled {
205			if closedChildCount == 0 {
206				p.Reason = "auto-cancel epic: all children cancelled, no work completed"
207				p.TargetStatus = StatusCancelled
208				p.CloseSatisfied = false
209				return p, true
210			}
211			p.Reason = "auto-close epic: all children reached terminal state"
212			p.TargetStatus = StatusClosed
213			p.CloseSatisfied = true
214			return p, true
215		}
216	
217		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
218			if b.Extra != nil {
219				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
220					return ReconcilePlan{}, false
221				}
222			}
223			p.Reason = "parent/epic work is owned by child beads"
224			p.SetFields = map[string]any{
225				ExtraExecutionElig:   false,
226				ExtraExecutionReason: "parent/epic container; execute child beads first",
227			}
228			return p, true
229		}
230	
231		return ReconcilePlan{}, false
232	}
